// Generated by Cypress Author — 2026-05-17
// Covers Product Name P2 features:
//   (K) Bulk Status Change — checkboxes, select-all (indeterminate), bulk action bar,
//       Set Active / Set Inactive / Deselect All, auto-deselect on filter/search change
//   (L) Product Count Badge Navigation — clicking badge > 0 navigates to product list
//       filtered by name; badge with count 0 is not a navigable button
//
// Strategy: real data seeding via API commands. Initial page data is SSR'd
// (no client-side list request on page load), so we do not intercept the initial
// list endpoint. Intercepts are used only for bulk update API calls.

import { faker } from '@faker-js/faker'

// ─── Helpers ─────────────────────────────────────────────────────────────────

/** Searches for a product name row by exact name text and waits for it to appear */
const waitForRow = (nameValue) => {
  cy.get('#searchInput_productNamePage').clear().type(nameValue)
  cy.get('#productNamesTable_productNamePage').should('contain', nameValue)
}

// ─── (K) Bulk Status Change — Checkbox & Select-All ─────────────────────────

describe('Product Name Bulk Action — Checkbox & Select-All', () => {
  let idA
  let nameA
  let idB
  let nameB

  before(() => {
    cy.setupApiAuthCookies()

    nameA = 'BLK-A-' + faker.string.alphanumeric(8)
    nameB = 'BLK-B-' + faker.string.alphanumeric(8)

    cy.AddProductName({ product_name: nameA, product_name_status: 'active' }).then((res) => {
      idA = res.body.productName.id
    })

    cy.AddProductName({ product_name: nameB, product_name_status: 'active' }).then((res) => {
      idB = res.body.productName.id
    })
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.setupApiAuthCookies()
    cy.visit('/main/inventory/product-name')
    cy.wait(1000)
    // Narrow the table to just the two seeded rows so select-all operates predictably
    cy.get('#searchInput_productNamePage').clear().type('BLK-')
    cy.get('#productNamesTable_productNamePage').should('contain', nameA).and('contain', nameB)
  })

  it('bulk action bar is hidden when no row is selected', () => {
    cy.get('#bulkActionBar_productNamePage').should('not.exist')
  })

  it('bulk action bar appears after selecting one row → shows "1 selected"', () => {
    cy.get(`#nameCheckbox_${idA}_productNamePage`).click()

    cy.get('#bulkActionBar_productNamePage').should('be.visible').and('contain', '1 selected')
  })

  it('bulk action bar disappears after deselecting the only selected row', () => {
    cy.get(`#nameCheckbox_${idA}_productNamePage`).click()
    cy.get('#bulkActionBar_productNamePage').should('be.visible')

    cy.get(`#nameCheckbox_${idA}_productNamePage`).click()
    cy.get('#bulkActionBar_productNamePage').should('not.exist')
  })

  it('selecting all rows via select-all checkbox → bar shows full count', () => {
    // With search='BLK-' we see 2 rows — select-all should report 2 selected
    cy.get('#selectAllNames_productNamePage').click()

    cy.get('#bulkActionBar_productNamePage').should('be.visible').and('contain', '2 selected')
  })

  it('select-all shows indeterminate state when only one of two rows is checked', () => {
    cy.get(`#nameCheckbox_${idA}_productNamePage`).click()

    // Radix Checkbox sets aria-checked="mixed" for the indeterminate state
    cy.get('#selectAllNames_productNamePage').should('have.attr', 'aria-checked', 'mixed')
  })

  it('select-all shows checked state when every visible row is selected', () => {
    cy.get('#selectAllNames_productNamePage').click()

    cy.get('#selectAllNames_productNamePage').should('have.attr', 'aria-checked', 'true')
  })

  it('Deselect All button clears selection → bulk action bar disappears', () => {
    cy.get(`#nameCheckbox_${idA}_productNamePage`).click()
    cy.get('#bulkActionBar_productNamePage').should('be.visible')

    cy.get('#bulkDeselectAllBtn_productNamePage').click()

    cy.get('#bulkActionBar_productNamePage').should('not.exist')
  })
})

// ─── (K) Set Active / Set Inactive ──────────────────────────────────────────

describe('Product Name Bulk Action — Set Active / Set Inactive', () => {
  let idActive
  let nameActive
  let idInactive
  let nameInactive

  before(() => {
    cy.setupApiAuthCookies()

    nameActive = 'BLK-ACT-' + faker.string.alphanumeric(8)
    nameInactive = 'BLK-INA-' + faker.string.alphanumeric(8)

    cy.AddProductName({ product_name: nameActive, product_name_status: 'active' }).then((res) => {
      idActive = res.body.productName.id
    })

    cy.AddProductName({ product_name: nameInactive, product_name_status: 'inactive' }).then(
      (res) => {
        idInactive = res.body.productName.id
      }
    )
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.setupApiAuthCookies()
    cy.visit('/main/inventory/product-name')
    cy.wait(1000)
  })

  it('Set Active sends PUT with active status for the selected row', () => {
    cy.intercept('PUT', `/api/inventory/v1/product-name/update/${idActive}`, {
      statusCode: 200,
      body: {
        success: true,
        productName: { id: idActive, product_name: nameActive, product_name_status: 'active' },
      },
    }).as('setActive')

    // Stub the list refresh that fires after bulk update completes
    cy.intercept('GET', '/api/inventory/v1/product-name/list').as('listRefresh')

    waitForRow(nameActive)
    cy.get(`#nameCheckbox_${idActive}_productNamePage`).click()
    cy.get('#bulkSetActiveBtn_productNamePage').click()

    cy.wait('@setActive').its('request.body').should('include', { product_name_status: 'active' })
  })

  it('Set Inactive sends PUT with inactive status for the selected row', () => {
    cy.intercept('PUT', `/api/inventory/v1/product-name/update/${idActive}`, {
      statusCode: 200,
      body: {
        success: true,
        productName: { id: idActive, product_name: nameActive, product_name_status: 'inactive' },
      },
    }).as('setInactive')

    cy.intercept('GET', '/api/inventory/v1/product-name/list').as('listRefresh')

    waitForRow(nameActive)
    cy.get(`#nameCheckbox_${idActive}_productNamePage`).click()
    cy.get('#bulkSetInactiveBtn_productNamePage').click()

    cy.wait('@setInactive')
      .its('request.body')
      .should('include', { product_name_status: 'inactive' })
  })

  it('after bulk Set Active succeeds, selection is cleared → bulk bar disappears', () => {
    cy.intercept('PUT', `/api/inventory/v1/product-name/update/${idActive}`, {
      statusCode: 200,
      body: {
        success: true,
        productName: { id: idActive, product_name: nameActive, product_name_status: 'active' },
      },
    }).as('setActive')

    cy.intercept('GET', '/api/inventory/v1/product-name/list').as('listRefresh')

    waitForRow(nameActive)
    cy.get(`#nameCheckbox_${idActive}_productNamePage`).click()
    cy.get('#bulkSetActiveBtn_productNamePage').click()

    cy.wait('@setActive')
    cy.wait('@listRefresh')

    // Selection is cleared after a successful bulk operation
    cy.get('#bulkActionBar_productNamePage').should('not.exist')
  })
})

// ─── (K) Auto-deselect on filter / search change ─────────────────────────────

describe('Product Name Bulk Action — Auto-deselect on Filter/Search Change', () => {
  let idActive
  let nameActive

  before(() => {
    cy.setupApiAuthCookies()

    nameActive = 'BLK-ADS-' + faker.string.alphanumeric(8)

    cy.AddProductName({ product_name: nameActive, product_name_status: 'active' }).then((res) => {
      idActive = res.body.productName.id
    })
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.setupApiAuthCookies()
    cy.visit('/main/inventory/product-name')
    cy.wait(1000)
  })

  it('selected active row is auto-deselected when inactive filter hides it', () => {
    waitForRow(nameActive)

    cy.get(`#nameCheckbox_${idActive}_productNamePage`).click()
    cy.get('#bulkActionBar_productNamePage').should('be.visible')

    // Switch to inactive filter — the active row is no longer visible
    cy.get('#filterSortBtn_productNamePage').click()
    cy.get('#filterOption_inactive_productNamePage').click()

    // The active row is now filtered out, so selectedIds should shrink to 0
    cy.get('#bulkActionBar_productNamePage').should('not.exist')
  })

  it('selected row is auto-deselected when search no longer matches it', () => {
    waitForRow(nameActive)

    cy.get(`#nameCheckbox_${idActive}_productNamePage`).click()
    cy.get('#bulkActionBar_productNamePage').should('be.visible')

    // Overwrite search with a string that cannot match our seeded row
    cy.get('#searchInput_productNamePage').clear().type('NONEXISTENT_xyz999abc')

    // Empty state means no visible rows — selection collapses to 0
    cy.get('#bulkActionBar_productNamePage').should('not.exist')
  })
})

// ─── (L) Product Count Badge Navigation ─────────────────────────────────────

describe('Product Name List — Product Count Badge Navigation', () => {
  let nameId
  let nameValue

  before(() => {
    cy.setupApiAuthCookies()

    nameValue = 'BADGE-NAV-' + faker.string.alphanumeric(6)

    // Create a name and link a product to it so product_count = 1
    cy.AddProductName({ product_name: nameValue, product_name_status: 'active', note: '' }).then(
      (nameRes) => {
        nameId = nameRes.body.productName.id

        cy.AddProductBrand({
          brand: 'BADGE-BRAND-' + faker.string.alphanumeric(6),
          brand_status: 'active',
          note: '',
        }).then((brandRes) => {
          cy.AddProduct({
            product_id: nameId,
            brand_id: brandRes.body.productBrand.id,
            type: faker.word.noun(),
            usage_quantity: 1,
            note: '',
            product_image: '',
          })
        })
      }
    )
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.setupApiAuthCookies()
    cy.visit('/main/inventory/product-name')
    cy.wait(1000)
    waitForRow(nameValue)
  })

  it('count badge > 0 is rendered as a button with an accessible aria-label', () => {
    cy.get(`#productCountBadge_${nameId}_productNamePage`)
      .should('exist')
      .and('have.attr', 'aria-label')
      .and('include', 'product')
  })

  it('clicking a count badge > 0 navigates to product list filtered by that name', () => {
    const expectedParam = encodeURIComponent(nameValue)

    cy.get(`#productCountBadge_${nameId}_productNamePage`).click()

    cy.url().should('include', '/main/inventory/product-list')
    cy.url().should('include', `name=${expectedParam}`)
  })

  it('count badge > 0 is keyboard-accessible (no tabindex="-1")', () => {
    cy.get(`#productCountBadge_${nameId}_productNamePage`).should('not.have.attr', 'tabindex', '-1')
  })
})

// ─── (L) Badge with count = 0 is not a button ────────────────────────────────

describe('Product Name List — Count Badge = 0 is Not Navigable', () => {
  let noProductNameId
  let noProductName

  before(() => {
    cy.setupApiAuthCookies()

    noProductName = 'BADGE-ZERO-' + faker.string.alphanumeric(6)

    // Create a name with no linked products → product_count stays 0
    cy.AddProductName({
      product_name: noProductName,
      product_name_status: 'active',
      note: '',
    }).then((res) => {
      noProductNameId = res.body.productName.id
    })
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.setupApiAuthCookies()
    cy.visit('/main/inventory/product-name')
    cy.wait(1000)
    waitForRow(noProductName)
  })

  it('count badge with value 0 is not rendered as a navigable button', () => {
    // The productCountBadge_{id} button only renders when product_count > 0
    cy.get(`#productCountBadge_${noProductNameId}_productNamePage`).should('not.exist')
  })
})
